mapper.select:
/* IOE장치 목록 조회 */ select rnum, device_ioe_idx, device_name, device_id, concat('(', inst_type_nm, ')', device_type_nm) as device_type_nm, device_type, site_id, device_stat_name, upload_timestamp from ( select @rownum := @rownum + 1 as rnum, page_tb.* from ( select a.device_id, a.device_name, a.site_id, a.device_type, case a.device_type when 1 then 'PCS' when 2 then 'BMS' when 3 then 'PV' when 4 then '부하측정기기' when 5 then 'PV모니터링기기' when 6 then 'ESS모니터링기기' when 7 then 'iSmart' when 8 then '총량기기' when 9 then 'AMI' else '' end as device_type_nm , case a.inst_type when 1 then '에너톡' when 2 then '로컬EMS' else '' end as inst_type_nm , b.device_ioe_idx, b.upload_timestamp, b.device_stat_name from tb_device a left outer join ( select device_ioe_idx, site_id, device_id, device_name, device_reg_id, serial_no, inst_type, inst_purpose, data_period, data_cnt, ct_capacity, ct_capacity_list, pw_capacity, ch_cnt, ch_purpose, provider, vr_device_id, vr_device_grp_id, vr_owner_id, vr_action, vr_stat, vr_mod_date, vr_error, tm_voltage, tm_pulse, tm_ct_ratio, tm_pt_tatio, network_conf, options, create_timestamp, create_date, upload_timestamp, upload_date, device_stat, reg_date , case device_stat when 1 then 'connect' else 'disconnect' end as device_stat_name from tb_device_ioe where (site_id, device_id, reg_date) in ( select site_id, device_id, max(reg_date) reg_date from tb_device_ioe group by site_id, device_id ) ) b on a.site_id = b.site_id and a.device_id = b.device_id where a.device_type in (4, 6, 7, 8)
and a.site_id = #{siteId }
union all select a.device_id, a.device_name, a.site_id, a.device_type, case a.device_type when 1 then 'PCS' when 2 then 'BMS' when 3 then 'PV' when 4 then '부하측정기기' when 5 then 'PV모니터링기기' when 6 then 'ESS모니터링기기' when 7 then 'iSmart' when 8 then '총량기기' when 9 then 'AMI' else '' end as device_type_nm , case a.inst_type when 1 then '에너톡' when 2 then '로컬EMS' else '' end as inst_type_nm , b.device_ioe_idx, b.upload_timestamp, b.device_stat_name from tb_device a left outer join ( select device_ami_idx as device_ioe_idx, site_id, device_id, device_name, device_stat, alarmMsg, voltage_r, voltage_s, voltage_t, current_r, current_s, current_t, frequency, active_power_r, active_power_s, active_power_t, reactive_power_lagging_r, reactive_power_lagging_s, reactive_power_lagging_t, reactive_power_leading_r, reactive_power_leading_s, reactive_power_leading_t, accum_active_power_r, accum_active_power_s, accum_active_power_t, accum_reactive_power_lagging_r, accum_reactive_power_lagging_s, accum_reactive_power_lagging_t, accum_reactive_power_leading_r, accum_reactive_power_leading_s, accum_reactive_power_leading_t, std_date as upload_timestamp, reg_date , case device_stat when 0 then 'Stop' when 1 then 'Run' when 2 then 'Fault' when 3 then 'Warning' else 'disconnect' end as device_stat_name from tb_device_ami where (site_id, device_id, reg_date) in ( select site_id, device_id, max(reg_date) reg_date from tb_device_ami group by site_id, device_id ) ) b on a.site_id = b.site_id and a.device_id = b.device_id where a.device_type = 9
and a.site_id = #{siteId }
) page_tb , ( select @rownum := 0 ) r ) f_tb
limit #{startNum }, #{pageRowCnt }

/* IOE장치 목록 건수 조회 */ select count(*) as listCnt from ( select @rownum := @rownum + 1 as rnum, page_tb.* from ( select a.device_id, a.device_name, a.site_id, a.device_type, case a.device_type when 1 then 'PCS' when 2 then 'BMS' when 3 then 'PV' when 4 then '부하측정기기' when 5 then 'PV모니터링기기' when 6 then 'ESS모니터링기기' when 7 then 'iSmart' when 8 then '총량기기' else '' end as device_type_nm , case a.inst_type when 1 then '에너톡' when 2 then '로컬EMS' else '' end as inst_type_nm , b.device_ioe_idx, b.upload_timestamp, b.device_stat_name from tb_device a left outer join ( select device_ioe_idx, site_id, device_id, device_name, device_reg_id, serial_no, inst_type, inst_purpose, data_period, data_cnt, ct_capacity, ct_capacity_list, pw_capacity, ch_cnt, ch_purpose, provider, vr_device_id, vr_device_grp_id, vr_owner_id, vr_action, vr_stat, vr_mod_date, vr_error, tm_voltage, tm_pulse, tm_ct_ratio, tm_pt_tatio, network_conf, options, create_timestamp, create_date, upload_timestamp, upload_date, device_stat, reg_date , case device_stat when 1 then 'connect' else 'disconnect' end as device_stat_name from tb_device_ioe where (site_id, device_id, reg_date) in ( select site_id, device_id, max(reg_date) reg_date from tb_device_ioe group by site_id, device_id ) ) b on a.site_id = b.site_id and a.device_id = b.device_id where a.device_type in (4, 6, 7, 8)
and a.site_id = #{siteId }
union all select a.device_id, a.device_name, a.site_id, a.device_type, case a.device_type when 1 then 'PCS' when 2 then 'BMS' when 3 then 'PV' when 4 then '부하측정기기' when 5 then 'PV모니터링기기' when 6 then 'ESS모니터링기기' when 7 then 'iSmart' when 8 then '총량기기' when 9 then 'AMI' else '' end as device_type_nm , case a.inst_type when 1 then '에너톡' when 2 then '로컬EMS' else '' end as inst_type_nm , b.device_ioe_idx, b.upload_timestamp, b.device_stat_name from tb_device a left outer join ( select device_ami_idx as device_ioe_idx, site_id, device_id, device_name, device_stat, alarmMsg, voltage_r, voltage_s, voltage_t, current_r, current_s, current_t, frequency, accum_active_power_r, accum_active_power_s, accum_active_power_t, accum_reactive_power_lagging_r, accum_reactive_power_lagging_s, accum_reactive_power_lagging_t, accum_reactive_power_leading_r, accum_reactive_power_leading_s, accum_reactive_power_leading_t, std_date as upload_timestamp, reg_date , case device_stat when 0 then 'Stop' when 1 then 'Run' when 2 then 'Fault' when 3 then 'Warning' else 'disconnect' end as device_stat_name from tb_device_ami where (site_id, device_id, reg_date) in ( select site_id, device_id, max(reg_date) reg_date from tb_device_ami group by site_id, device_id ) ) b on a.site_id = b.site_id and a.device_id = b.device_id where a.device_type = 9
and a.site_id = #{siteId }
) page_tb , ( select @rownum := 0 ) r ) f_tb

/* PCS장치 목록 조회 */ select rnum, device_pcs_idx, device_name, device_id, concat('(', inst_type_nm, ')', device_type_nm) as device_type_nm, device_type, site_id, pcs_status_name, alarm_msg, std_date from ( select @rownum := @rownum + 1 as rnum, page_tb.* from ( select a.device_id, a.device_name, a.site_id, a.device_type, case a.device_type when 1 then 'PCS' when 2 then 'BMS' when 3 then 'PV' when 4 then '부하측정기기' when 5 then 'PV모니터링기기' when 6 then 'ESS모니터링기기' when 7 then 'iSmart' when 8 then '총량기기' when 9 then 'AMI' else '' end as device_type_nm , case a.inst_type when 1 then '에너톡' when 2 then '로컬EMS' else '' end as inst_type_nm , b.device_pcs_idx, b.device_stat_name, b.pcs_status_name, b.alarm_msg, b.std_date from tb_device a left outer join ( select device_pcs_idx, site_id, device_id, device_name, device_stat, alarm_msg, ac_voltage, ac_power, ac_current, ac_freq, ac_set_power, ac_pf, dc_voltage, dc_power, dc_current, dc_freq, dc_set_power, dc_pf, std_date, reg_date , case device_stat when 1 then 'Schedule' when 2 then 'Command' else 'disconnect' end as device_stat_name , pcs_status , case pcs_status when 0 then 'Off' when 1 then 'On' when 2 then 'Fault' when 3 then 'Warning' else 'disconnect' end as pcs_status_name from tb_device_pcs where (site_id, device_id, reg_date) in ( select site_id, device_id, max(reg_date) reg_date from tb_device_pcs group by site_id, device_id ) ) b on a.site_id = b.site_id and a.device_id = b.device_id where a.device_type = 1
and a.site_id = #{siteId }
order by a.device_id ) page_tb , ( select @rownum := 0 ) r ) f_tb
limit #{startNum }, #{pageRowCnt }

/* PCS장치 목록 건수 조회 */ select count(*) as listCnt from ( select @rownum := @rownum + 1 as rnum, page_tb.* from ( select a.device_id, a.device_name, a.site_id, a.device_type, case a.device_type when 1 then 'PCS' when 2 then 'BMS' when 3 then 'PV' when 4 then '부하측정기기' when 5 then 'PV모니터링기기' when 6 then 'ESS모니터링기기' when 7 then 'iSmart' when 8 then '총량기기' when 9 then 'AMI' else '' end as device_type_nm , case a.inst_type when 1 then '에너톡' when 2 then '로컬EMS' else '' end as inst_type_nm , b.device_pcs_idx, b.device_stat_name, b.alarm_msg, b.std_date from tb_device a left outer join ( select device_pcs_idx, site_id, device_id, device_name, device_stat, alarm_msg, ac_voltage, ac_power, ac_current, ac_freq, ac_set_power, ac_pf, dc_voltage, dc_power, dc_current, dc_freq, dc_set_power, dc_pf, std_date, reg_date , case device_stat when 1 then 'Schedule' when 2 then 'Command' else 'disconnect' end as device_stat_name , "" as cd_status , pcs_status , case pcs_status when 0 then 'Off' when 1 then 'On' when 2 then 'Fault' when 3 then 'Warning' else 'disconnect' end as pcs_status_name from tb_device_pcs where (site_id, device_id, reg_date) in ( select site_id, device_id, max(reg_date) reg_date from tb_device_pcs group by site_id, device_id ) ) b on a.site_id = b.site_id and a.device_id = b.device_id where a.device_type = 1
and a.site_id = #{siteId }
) page_tb , ( select @rownum := 0 ) r ) f_tb

/* BMS장치 목록 조회 */ select rnum, device_bms_idx, device_name, device_id, concat('(', inst_type_nm, ')', device_type_nm) as device_type_nm, device_type, site_id, device_stat_name, alarm_msg, std_date from ( select @rownum := @rownum + 1 as rnum, page_tb.* from ( select a.device_id, a.device_name, a.site_id, a.device_type, case a.device_type when 1 then 'PCS' when 2 then 'BMS' when 3 then 'PV' when 4 then '부하측정기기' when 5 then 'PV모니터링기기' when 6 then 'ESS모니터링기기' when 7 then 'iSmart' when 8 then '총량기기' when 9 then 'AMI' else '' end as device_type_nm , case a.inst_type when 1 then '에너톡' when 2 then '로컬EMS' else '' end as inst_type_nm , b.device_bms_idx, b.device_stat_name, b.alarm_msg, b.std_date from tb_device a left outer join ( select device_bms_idx, site_id, device_id, device_name, device_stat, sys_soc, curr_soc, sys_soh, sys_voltage, sys_current, dod, std_date, reg_date , case device_stat when 0 then 'Idle' when 1 then 'Charge' when 2 then 'Discharge' when 3 then 'MainS/W on/off' when 4 then 'Off-line' when 5 then 'Ready' else 'disconnect' end as device_stat_name , alarm_msg from tb_device_bms where (site_id, device_id, reg_date) in ( select site_id, device_id, max(reg_date) reg_date from tb_device_bms group by site_id, device_id ) ) b on a.site_id = b.site_id and a.device_id = b.device_id where a.device_type = 2
and a.site_id = #{siteId }
order by a.device_id ) page_tb , ( select @rownum := 0 ) r ) f_tb
limit #{startNum }, #{pageRowCnt }

/* BMS장치 건수 조회 */ select count(*) as listCnt from ( select @rownum := @rownum + 1 as rnum, page_tb.* from ( select a.device_id, a.device_name, a.site_id, a.device_type, case a.device_type when 1 then 'PCS' when 2 then 'BMS' when 3 then 'PV' when 4 then '부하측정기기' when 5 then 'PV모니터링기기' when 6 then 'ESS모니터링기기' when 7 then 'iSmart' when 8 then '총량기기' when 9 then 'AMI' else '' end as device_type_nm , case a.inst_type when 1 then '에너톡' when 2 then '로컬EMS' else '' end as inst_type_nm , b.device_bms_idx, b.device_stat_name, b.alarm_msg, b.std_date from tb_device a left outer join ( select device_bms_idx, site_id, device_id, device_name, device_stat, sys_soc, curr_soc, sys_soh, sys_voltage, sys_current, dod, std_date, reg_date , case device_stat when 0 then 'Idle' when 1 then 'Charge' when 2 then 'Discharge' when 3 then 'MainS/W on/off' when 4 then 'Off-line' when 5 then 'Ready' else 'disconnect' end as device_stat_name , alarm_msg from tb_device_bms where (site_id, device_id, reg_date) in ( select site_id, device_id, max(reg_date) reg_date from tb_device_bms group by site_id, device_id ) ) b on a.site_id = b.site_id and a.device_id = b.device_id where a.device_type = 2
and a.site_id = #{siteId }
) page_tb , ( select @rownum := 0 ) r ) f_tb

/* PV장치 목록 조회 */ select rnum, device_pv_idx, device_name, device_id, concat('(', inst_type_nm, ')', device_type_nm) as device_type_nm, device_type, site_id, device_stat_name, temp, alarm_msg, std_date from ( select @rownum := @rownum + 1 as rnum, page_tb.* from ( select a.device_id, a.device_name, a.site_id, a.device_type, case a.device_type when 1 then 'PCS' when 2 then 'BMS' when 3 then 'PV' when 4 then '부하측정기기' when 5 then 'PV모니터링기기' when 6 then 'ESS모니터링기기' when 7 then 'iSmart' when 8 then '총량기기' when 9 then 'AMI' else '' end as device_type_nm , case a.inst_type when 1 then '에너톡' when 2 then '로컬EMS' else '' end as inst_type_nm , b.device_pv_idx, b.device_stat_name, b.alarm_msg, b.std_date, b.temp from tb_device a left outer join ( select device_pv_idx, site_id, device_id, device_name, device_stat, alarm_msg, temp, tot_power, std_date, reg_date , case device_stat when 0 then 'Stop' when 1 then 'Run' else 'disconnect' end as device_stat_name from tb_device_pv where (site_id, device_id, reg_date) in ( select site_id, device_id, max(reg_date) reg_date from tb_device_pv group by site_id, device_id ) ) b on a.site_id = b.site_id and a.device_id = b.device_id where a.device_type in (3, 5)
and a.site_id = #{siteId }
order by a.device_id ) page_tb , ( select @rownum := 0 ) r ) f_tb
limit #{startNum }, #{pageRowCnt }

/* PV장치 건수 조회 */ select count(*) as listCnt from ( select @rownum := @rownum + 1 as rnum, page_tb.* from ( select a.device_id, a.device_name, a.site_id, device_type, case a.device_type when 1 then 'PCS' when 2 then 'BMS' when 3 then 'PV' when 4 then '부하측정기기' when 5 then 'PV모니터링기기' when 6 then 'ESS모니터링기기' when 7 then 'iSmart' when 8 then '총량기기' when 9 then 'AMI' else '' end as device_type_nm , case a.inst_type when 1 then '에너톡' when 2 then '로컬EMS' else '' end as inst_type_nm , b.device_pv_idx, b.device_stat_name, b.alarm_msg, b.std_date, b.temp from tb_device a left outer join ( select device_pv_idx, site_id, device_id, device_name, device_stat, alarm_msg, temp, tot_power, std_date, reg_date , case device_stat when 0 then 'Stop' when 1 then 'Run' else 'disconnect' end as device_stat_name from tb_device_pv where (site_id, device_id, reg_date) in ( select site_id, device_id, max(reg_date) reg_date from tb_device_pv group by site_id, device_id ) ) b on a.site_id = b.site_id and a.device_id = b.device_id where a.device_type in (3, 5)
and a.site_id = #{siteId }
) page_tb , ( select @rownum := 0 ) r ) f_tb

/* 장치 건수 조회 */ select count(*) as listCnt from ( select @rownum := @rownum + 1 as rnum, page_tb.* from ( select a.device_id, a.site_id, a.user_idx, a.device_name, a.device_grp_idx, a.device_type, a.inst_type, ioe.upload_date, ioe.device_stat, pcs.ac_power, pcs.dc_power, bms.sys_soc, pv.tot_power, ami.device_stat as ami_device_stat, a.del_yn, a.reg_uid, a.reg_date, a.mod_uid, a.mod_date from tb_device a left outer join ( select device_ioe_idx, site_id, device_id, device_name, device_reg_id, serial_no, inst_type, inst_purpose, data_period, data_cnt, ct_capacity, ct_capacity_list, pw_capacity, ch_cnt, ch_purpose, provider, vr_device_id, vr_device_grp_id, vr_owner_id, vr_action, vr_stat, vr_mod_date, vr_error, tm_voltage, tm_pulse, tm_ct_ratio, tm_pt_tatio, network_conf, options, create_timestamp, create_date, upload_timestamp, upload_date, device_stat, reg_date from tb_device_ioe where (site_id, device_id, reg_date) in ( select site_id, device_id, max(reg_date) reg_date from tb_device_ioe group by site_id, device_id )
and site_id = #{siteId }
order by device_id ) ioe on a.device_id = ioe.device_id and a.device_type in (4, 6, 7, 8) left outer join ( select device_pcs_idx, site_id, device_id, device_name, device_stat, alarm_msg, ac_voltage, ac_power, ac_current, ac_freq, ac_set_power, ac_pf, dc_voltage, dc_power, dc_current, dc_freq, dc_set_power, dc_pf, std_date, reg_date from tb_device_pcs where (site_id, device_id, reg_date) in ( select site_id, device_id, max(reg_date) reg_date from tb_device_pcs group by site_id, device_id )
and site_id = #{siteId }
order by device_id ) pcs on a.device_id = pcs.device_id and a.device_type = 1 left outer join ( select device_bms_idx, site_id, device_id, device_name, device_stat, sys_soc, curr_soc, sys_soh, sys_voltage, sys_current, dod, std_date, reg_date from tb_device_bms where (site_id, device_id, reg_date) in ( select site_id, device_id, max(reg_date) reg_date from tb_device_bms group by site_id, device_id )
and site_id = #{siteId }
order by device_id ) bms on a.device_id = bms.device_id and a.device_type = 2 left outer join ( select device_pv_idx, site_id, device_id, device_name, device_stat, alarm_msg, temp, tot_power, std_date, reg_date from tb_device_pv where (site_id, device_id, reg_date) in ( select site_id, device_id, max(reg_date) reg_date from tb_device_pv group by site_id, device_id )
and site_id = #{siteId }
order by device_id ) pv on a.device_id = pv.device_id and a.device_type = 3 left outer join ( select device_ami_idx, site_id, device_id, device_name, device_stat, alarmMsg, voltage_r, voltage_s, voltage_t, current_r, current_s, current_t, frequency, accum_active_power_r, accum_active_power_s, accum_active_power_t, accum_reactive_power_lagging_r, accum_reactive_power_lagging_s, accum_reactive_power_lagging_t, accum_reactive_power_leading_r, accum_reactive_power_leading_s, accum_reactive_power_leading_t, std_date, reg_date from tb_device_ami where (site_id, device_id, reg_date) in ( select site_id, device_id, max(reg_date) reg_date from tb_device_ami group by site_id, device_id )
and site_id = #{siteId }
order by device_id ) ami on a.device_id = ami.device_id and a.device_type = 9 where a.del_yn = 'N'
and a.site_id = #{siteId }
order by a.device_id ) page_tb , ( select @rownum := 0 ) r ) f_tb

/* 장치 상세 조회 */
select 
	device_id, site_id, user_idx, device_name, device_grp_idx, 
	device_type, inst_type, del_yn, reg_uid, reg_date, mod_uid, mod_date
from tb_device
where site_id = #{siteId} 
and device_id = #{deviceId}
and device_type = #{deviceType}

select device.device_id, device.device_type, alarm.alarm_type, alarm.alarm_act_yn, alarm.alarm_msg, alarm.std_date from tb_device device left outer join ( select t1.* from ( SELECT row_number() over (partition by device_type, device_id order by std_date desc) as rn, AL.* FROM tb_alarm AL WHERE AL.site_id = #{siteId}
and AL.device_type in ('V', 'A')
and AL.device_type = #{deviceType}
) t1 where rn = 1 ) alarm on device.site_id = alarm.site_id and device.device_type = alarm.device_type and device.device_id = alarm.device_id where device.site_id = #{siteId}
and device.device_type in ('V', 'A')
and device.device_type = #{deviceType}

/* 발전량 조회 */ select DATE_FORMAT(update_date,'%Y%m') monthdate, sum(pv_volt) as sum_pv_volt, sum(pv_curr) as sum_pv_curr, sum(pv_watt) as sum_pv_watt, sum(now_pwr) as sum_now_pwr, sum(daily_pwr) as sum_daily_pwr, sum(tot_power) as sum_tot_power, sum(ac_volt_rs) as sum_ac_volt_rs, sum(ac_volt_st) as sum_ac_volt_st, sum(ac_volt_tr) as sum_ac_volt_tr, sum(ac_volt_r) as sum_ac_volt_r, sum(ac_volt_s) as sum_ac_volt_s, sum(ac_volt_t) as sum_ac_volt_t, sum(ac_curr_r) as sum_ac_curr_r, sum(ac_curr_s) as sum_ac_curr_s, sum(ac_curr_t) as sum_ac_curr_t, sum(powerfactor) as sum_powerfactor from tb_device_inverter
where DATE_FORMAT(update_date, '%Y') in (DATE_FORMAT(now(),'%Y'), date_format(DATE_SUB(now(),INTERVAL 1 YEAR), '%Y')) and DATE_FORMAT(update_date, '%m') <= DATE_FORMAT(now(), '%m')
and site_id = #{siteId}
group by monthdate

        /* 인버터별 발전량 조회 -> 이용률로 변경예정 */
		select sum(tot_power) as sum_tot_power 
 		from tb_device_inverter

        where DATE_FORMAT(update_date, '%Y') = (DATE_FORMAT(now(),'%Y'))
		  and DATE_FORMAT(update_date, '%m') <= DATE_FORMAT(now(), '%m')

		  and inverter_id = #{inverterId}
		  and site_id = #{siteId}
		group by DATE_FORMAT(update_date, '%m');

        /* 인버터별 발전량 조회 -> 이용률로 변경예정 */
		select device_id
	    from tb_device
	    where device_type = 'i'

			and site_id = #{siteId}
